 1→import { createContext, useCallback, useContext, useRef, useState } from 'react';
 2→import ToastContainer from './ToastContainer';
 3→
 4→const ToastContext = createContext(null);
 5→
 6→let toastIdCounter = 0;
 7→
 8→export const ToastProvider = ({ children }) => {
 9→    const [toasts, setToasts] = useState([]);
10→    const timersRef = useRef({});
11→
12→    const removeToast = useCallback((id) => {
13→        clearTimeout(timersRef.current[id]);
14→        delete timersRef.current[id];
15→        setToasts((prev) => prev.filter((t) => t.id !== id));
16→    }, []);
17→
18→    const addToast = useCallback((type, message, duration) => {
19→        const id = ++toastIdCounter;
20→        const autoMs = duration ?? (type === 'error' || type === 'warning' ? 5000 : 3500);
21→
22→        setToasts((prev) => {
23→            const next = [...prev, { id, type, message }];
24→            return next.length > 3 ? next.slice(-3) : next;
25→        });
26→
27→        timersRef.current[id] = setTimeout(() => removeToast(id), autoMs);
28→        return id;
29→    }, [removeToast]);
30→
31→    const toast = {
32→        success: (msg, ms) => addToast('success', msg, ms),
33→        error: (msg, ms) => addToast('error', msg, ms),
34→        warning: (msg, ms) => addToast('warning', msg, ms),
35→        info: (msg, ms) => addToast('info', msg, ms),
36→    };
37→
38→    return (
39→        <ToastContext.Provider value={{ toast }}>
40→            {children}
41→            <ToastContainer toasts={toasts} onDismiss={removeToast} />
42→        </ToastContext.Provider>
43→    );
44→};
45→
46→export const useToast = () => {
47→    const ctx = useContext(ToastContext);
48→    if (!ctx) throw new Error('useToast must be used within ToastProvider');
49→    return ctx;
50→};
