 1→import { createPortal } from 'react-dom';
 2→import { AnimatePresence } from 'framer-motion';
 3→import Toast from './Toast';
 4→import './Toast.css';
 5→
 6→const ToastContainer = ({ toasts, onDismiss }) => {
 7→    return createPortal(
 8→        <div className="toast-container" aria-label="Notifications">
