```javascript
import { createPortal } from 'react-dom';
import { AnimatePresence } from 'framer-motion';
import Toast from './Toast';
import './Toast.css';

const ToastContainer = ({ toasts, onDismiss }) => {
    return createPortal(
        <div className="toast-container" aria-label="Notifications">
            <AnimatePresence mode="popLayout">
                {toasts.map((t) => (
                    <Toast key={t.id} {...t} onDismiss={onDismiss} />
                ))}
            </AnimatePresence>
        </div>,
        document.body
    );
};

export default ToastContainer;
```

**Key features:**
- Portals toast DOM to `document.body` (renders outside component tree)
- Uses Framer Motion's `AnimatePresence` with `mode="popLayout"` for smooth exit animations
- Maps over toasts array and renders individual Toast components

